#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long x, y;
        for(long long i=0;i<N;i++) scanf("%lld %lld", &x, &y); // coordinates ignored
        long long cur=N, ans=N;
        while(cur>=6){
            cur/=2; // floor division
            ans+=cur;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

