const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  let N = Number(input[idx++]);
  // skip coordinates
  idx += 2 * N;
  let cur = N;
  let ans = N;
  while (cur >= 6) {
    cur = Math.floor(cur / 2);
    ans += cur;
  }
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));
